SELECT id, paper_performance, product_type, pattern_characteristic, hot_stamping_type, compatibility, pre_processing_step_id, product_type_id, pattern_characteristic_id, hot_stamping_type_id, post_processing_step_id, notice_ids, created_at, updated_at FROM hot_stamping_compatibility WHERE compatibility IN ('V', '▷')
AND paper_performance = #{paperPerformance}
AND product_type = #{productType}
AND pattern_type = #{patternType}
AND hot_stamping_type IN
#{type}
ORDER BY paper_performance ASC, product_type_id ASC NULLS LAST, pattern_characteristic_id ASC NULLS LAST, hot_stamping_type_id ASC NULLS LAST, id ASC

SELECT COUNT(*)
FROM hot_stamping_compatibility
WHERE hot_stamping_type_id = #{hotStampingTypeId}

SELECT DISTINCT paper_performance 
FROM hot_stamping_compatibility
WHERE 1=1

    AND product_type_id = #{productTypeId}


    AND pattern_characteristic_id = #{patternCharacteristicId}


    AND hot_stamping_type_id = #{hotStampingTypeId}


    AND pre_processing_step_id = #{preProcessingStepId}


    AND post_processing_step_id = #{postProcessingStepId}

AND compatibility IN ('V', '▷')
ORDER BY paper_performance

SELECT hsc.id, hsc.paper_performance, hsc.product_type, hsc.pattern_characteristic, hsc.hot_stamping_type, hsc.compatibility, hsc.created_at, hsc.updated_at, hsc.product_type_id, hsc.pattern_characteristic_id, hsc.hot_stamping_type_id, hsc.pre_processing_step_id, hsc.post_processing_step_id, hsc.notice_ids FROM hot_stamping_compatibility hsc WHERE 1=1
AND hsc.product_type_id = #{productTypeId}
AND hsc.pattern_characteristic_id = #{patternCharacteristicId}
AND hsc.hot_stamping_type_id = #{hotStampingTypeId}
AND hsc.pre_processing_step_id = #{preProcessingStepId}
AND hsc.post_processing_step_id = #{postProcessingStepId}
ORDER BY hsc.paper_performance ASC, hsc.product_type_id ASC NULLS LAST, hsc.pattern_characteristic_id ASC NULLS LAST, hsc.hot_stamping_type_id ASC NULLS LAST, hsc.id ASC

SELECT id, paper_performance, product_type, pattern_characteristic, hot_stamping_type, compatibility, pre_processing_step_id, product_type_id, pattern_characteristic_id, hot_stamping_type_id, post_processing_step_id, notice_ids, created_at, updated_at FROM hot_stamping_compatibility WHERE compatibility IN ('V', '▷')
AND product_type = #{productType}
AND pattern_characteristic = #{patternCharacteristic}
AND hot_stamping_type = #{hotStampingType}
ORDER BY paper_performance ASC, product_type_id ASC NULLS LAST, pattern_characteristic_id ASC NULLS LAST, hot_stamping_type_id ASC NULLS LAST, id ASC

SELECT COUNT(*) 
FROM hot_stamping_compatibility
WHERE product_type_id = #{productTypeId}
  AND pattern_characteristic_id = #{patternCharacteristicId}
  AND hot_stamping_type_id = #{hotStampingTypeId}


          AND pre_processing_step_id = #{preProcessingStepId}


          AND pre_processing_step_id IS NULL




          AND post_processing_step_id = #{postProcessingStepId}


          AND post_processing_step_id IS NULL


  AND paper_performance = #{paperPerformance}
  AND compatibility = #{compatibility}

      AND id != #{excludeId}

SELECT DISTINCT unnest(notice_ids)
FROM hot_stamping_compatibility
WHERE notice_ids IS NOT NULL
AND array_length(notice_ids, 1) > 0
AND compatibility IN ('V', '▷')

    AND product_type_id = #{productTypeId}


    AND pattern_characteristic_id = #{patternId}


    AND paper_performance IN

        #{paperType}
